 30→describe("Brain-auth trace attribution", () => {
 31→  it("creates a trace attributed to the workspace from the proxy token (not headers)", async () => {
 32→    const { baseUrl, surreal } = getRuntime();
 33→
 34→    const user = await createProxyTestUser(baseUrl, surreal, "trace");
 35→
 36→    // Given Priya has a valid proxy token
 37→    const tokenResponse = await requestProxyToken(baseUrl, user.sessionHeaders, user.workspaceId);
 38→    const { proxy_token } = await tokenResponse.json() as { proxy_token: string };
 39→
 40→    // When she makes a Brain-auth proxy request
 41→    const proxyResponse = await sendBrainAuthProxyRequest(baseUrl, proxy_token);
 42→
 43→    // Note: If the server has no ANTHROPIC_API_KEY, it returns 500 — skip LLM/trace assertions.
 44→    if (proxyResponse.status === 500) {
 45→      const errBody = await proxyResponse.json() as { error?: { message?: string } };
 46→      if (errBody.error?.message?.includes("API key not configured")) {
