 93→// Scenario: Token expiry detection (simulated SessionStart check)
 94→// ---------------------------------------------------------------------------
 95→describe("Token expiry detection", () => {
 96→  it("identifies tokens expiring within 7 days as needing refresh", () => {
 97→    // Given a proxy token that expires in 3 days
 98→    const expiresAt = new Date(Date.now() + 3 * 24 * 60 * 60 * 1000);
 99→    const daysUntilExpiry = (expiresAt.getTime() - Date.now()) / (1000 * 60 * 60 * 24);
100→
101→    // When SessionStart checks the expiry
102→    const needsRefresh = daysUntilExpiry <= 7;
103→
104→    // Then it detects the token needs refreshing
105→    expect(needsRefresh).toBe(true);
106→  });
107→
108→  it("does not flag tokens with more than 7 days remaining", () => {
109→    // Given a proxy token that expires in 30 days
110→    const expiresAt = new Date(Date.now() + 30 * 24 * 60 * 60 * 1000);
111→    const daysUntilExpiry = (expiresAt.getTime() - Date.now()) / (1000 * 60 * 60 * 24);
112→
113→    // When SessionStart checks the expiry
114→    const needsRefresh = daysUntilExpiry <= 7;
115→
116→    // Then it does not flag for refresh
117→    expect(needsRefresh).toBe(false);
118→  });
119→
120→  it("detects already-expired tokens", () => {
121→    // Given a proxy token that expired yesterday
122→    const expiresAt = new Date(Date.now() - 1 * 24 * 60 * 60 * 1000);
123→    const daysUntilExpiry = (expiresAt.getTime() - Date.now()) / (1000 * 60 * 60 * 24);
124→
125→    // When SessionStart checks the expiry
126→    const isExpired = daysUntilExpiry <= 0;
127→
128→    // Then it detects the token is expired
129→    expect(isExpired).toBe(true);
130→  });
131→});
