100→    // Given Priya had a proxy token that was then revoked by re-issuance
101→    const firstResponse = await requestProxyToken(baseUrl, user.sessionHeaders, user.workspaceId);
102→    const { proxy_token: firstToken } = await firstResponse.json() as { proxy_token: string };
103→
104→    // Re-issue to revoke the first token
105→    await requestProxyToken(baseUrl, user.sessionHeaders, user.workspaceId);
106→
107→    // When a request uses the revoked (first) token
108→    const proxyResponse = await sendBrainAuthProxyRequest(baseUrl, firstToken);
109→
110→    // Then the proxy returns 401
111→    expect(proxyResponse.status).toBe(401);
112→  }, 15_000);
