 42→export async function resolveIntentContext(input: {
 43→  surreal: Surreal;
 44→  embeddingModel: Parameters<typeof createEmbeddingVector>[0];
 45→  embeddingDimension: number;
 46→  workspaceRecord: RecordId<"workspace", string>;
 47→  workspaceName: string;
 48→  intent: string;
 49→  cwd?: string;
 50→  paths?: string[];
 51→}): Promise<IntentContextResult> {
 52→  const { surreal, embeddingModel, embeddingDimension, workspaceRecord, workspaceName, intent } = input;
 53→
 54→  const contextResult = await resolveContextLevel({
 55→    surreal, embeddingModel, embeddingDimension, workspaceRecord, workspaceName, intent,
 56→    cwd: input.cwd, paths: input.paths,
 57→  });
 58→
 59→  // Load learnings for MCP agent type (no contextEmbedding — precedents excluded)
 60→  const workspaceId = workspaceRecord.id as string;
 61→  const learningsResult = await loadActiveLearnings({
 62→    surreal,
 63→    workspaceId,
 64→    agentType: "mcp",
 65→  });
