 88→  cwd?: string;
 89→  paths?: string[];
 90→}): Promise<{ level: "task"; data: TaskContextPacket } | { level: "project"; data: ContextPacket } | { level: "workspace"; data: WorkspaceOverview }> {
 91→  const { surreal, embeddingModel, embeddingDimension, workspaceRecord, workspaceName, intent } = input;
 92→
 93→  // Step 1: Explicit entity references in intent text
 94→  const explicitTask = extractEntityRef(intent, "task");
 95→  if (explicitTask) {
 96→    try {
 97→      const data = await buildTaskContext({ surreal, workspaceRecord, workspaceName, taskId: explicitTask });
 98→      return { level: "task", data };
 99→    } catch {
100→      // Task not found — fall through to other strategies
101→    }
102→  }
103→
104→  const explicitProject = extractEntityRef(intent, "project");
105→  if (explicitProject) {
106→    try {
107→      const projectRecord = new RecordId("project", explicitProject);
108→      const data = await buildProjectContext({ surreal, workspaceRecord, workspaceName, projectRecord });
109→      return { level: "project", data };
110→    } catch {
111→      // Project not found — fall through
112→    }
113→  }
114→
115→  // Step 2: Single-project shortcut
116→  const projects = await listWorkspaceProjects(surreal, workspaceRecord);
117→  if (projects.length === 1) {
118→    const data = await buildProjectContext({
119→      surreal,
120→      workspaceRecord,
121→      workspaceName,
122→      projectRecord: projects[0].id,
123→    });
124→    return { level: "project", data };
125→  }
126→
127→  // Step 3: Vector search — embed intent, match against all entities
128→  let queryEmbedding: number[] | undefined;
129→  try {
130→    queryEmbedding = await createEmbeddingVector(embeddingModel, intent, embeddingDimension);
131→  } catch {
132→    // Embedding model unavailable — fall through to path/workspace fallbacks
133→  }
134→  if (queryEmbedding) {
135→    const results = await searchEntitiesByEmbedding({
136→      surreal,
137→      workspaceRecord,
138→      queryEmbedding,
139→      limit: 5,
140→    });
141→
142→    if (results.length > 0 && results[0].score > 0.3) {
143→      const top = results[0];
144→
145→      if (top.kind === "task") {
146→        const taskId = top.id.includes(":") ? top.id.split(":")[1] : top.id;
147→        try {
148→          const data = await buildTaskContext({ surreal, workspaceRecord, workspaceName, taskId });
149→          return { level: "task", data };
150→        } catch {
151→          // Fall through
152→        }
153→      }
154→
155→      // For project/feature matches, or task fallback: resolve to project context
156→      const projectRecord = await resolveProjectFromMatch(surreal, top);
157→      if (projectRecord) {
158→        const data = await buildProjectContext({ surreal, workspaceRecord, workspaceName, projectRecord });
159→        return { level: "project", data };
160→      }
161→    }
162→  }
163→
164→  // Step 4: Path matching — match directory names against project names
165→  const allPaths = [...(input.paths ?? [])];
166→  if (input.cwd) allPaths.push(input.cwd);
167→
168→  if (allPaths.length > 0 && projects.length > 0) {
169→    const matched = matchPathToProject(allPaths, projects);
170→    if (matched) {
171→      const data = await buildProjectContext({ surreal, workspaceRecord, workspaceName, projectRecord: matched });
172→      return { level: "project", data };
173→    }
174→  }
175→
176→  // Step 5: Fallback — workspace overview
177→  const data = await buildWorkspaceOverview({ surreal, workspaceRecord, workspaceName });
178→  return { level: "workspace", data };
179→}
