185→/** Extract explicit entity reference like `task:abc123` or `project:def456` from text */
186→function extractEntityRef(text: string, entityType: string): string | undefined {
187→  const pattern = new RegExp(`\\b${entityType}:([a-zA-Z0-9_-]+)`, "i");
188→  const match = text.match(pattern);
189→  return match ? match[1] : undefined;
190→}
