192→/** List all projects in a workspace */
193→async function listWorkspaceProjects(
194→  surreal: Surreal,
195→  workspaceRecord: RecordId<"workspace", string>,
196→): Promise<ProjectRow[]> {
197→  const [rows] = await surreal
198→    .query<[ProjectRow[]]>(
199→      `SELECT id, name, status, description FROM project
200→       WHERE id IN (SELECT VALUE out FROM has_project WHERE \`in\` = $workspace);`,
201→      { workspace: workspaceRecord },
202→    )
203→    .collect<[ProjectRow[]]>();
204→  return rows;
