207→/** Resolve a search match to a project RecordId */
208→async function resolveProjectFromMatch(
209→  surreal: Surreal,
210→  match: { id: string; kind: SearchEntityKind },
211→): Promise<RecordId<"project", string> | undefined> {
212→  if (match.kind === "project") {
213→    const rawId = match.id.includes(":") ? match.id.split(":")[1] : match.id;
214→    return new RecordId("project", rawId);
215→  }
216→
217→  // For task/decision/question/suggestion: find project via belongs_to
218→  // For feature: find project via has_feature (reverse)
219→  const rawId = match.id.includes(":") ? match.id.split(":")[1] : match.id;
220→  const table = match.kind;
221→  const entityRecord = new RecordId(table, rawId);
222→
223→  if (match.kind === "feature") {
224→    const [rows] = await surreal
225→      .query<[Array<{ in: RecordId<"project", string> }>]>(
226→        `SELECT \`in\` FROM has_feature WHERE out = $entity LIMIT 1;`,
227→        { entity: entityRecord },
228→      )
229→      .collect<[Array<{ in: RecordId<"project", string> }>]>();
230→    return rows.length > 0 ? rows[0].in : undefined;
231→  }
232→
233→  // task, decision, question, suggestion → belongs_to → project
234→  const [rows] = await surreal
235→    .query<[Array<{ out: RecordId<"project", string> }>]>(
236→      `SELECT out FROM belongs_to WHERE \`in\` = $entity AND record::tb(out) = "project" LIMIT 1;`,
237→      { entity: entityRecord },
238→    )
239→    .collect<[Array<{ out: RecordId<"project", string> }>]>();
240→  return rows.length > 0 ? rows[0].out : undefined;
241→}
242→
243→/** Match directory paths against project names using normalized token overlap */
244→function matchPathToProject(
245→  paths: string[],
246→  projects: ProjectRow[],
247→): RecordId<"project", string> | undefined {
248→  const pathTokens = new Set<string>();
249→  for (const p of paths) {
250→    for (const segment of p.split("/").filter(Boolean)) {
251→      for (const token of segment.toLowerCase().replace(/[^a-z0-9]/g, " ").split(/\s+/)) {
252→        if (token.length > 2) pathTokens.add(token);
253→      }
254→    }
255→  }
256→
257→  if (pathTokens.size === 0) return undefined;
258→
259→  let bestProject: ProjectRow | undefined;
260→  let bestOverlap = 0;
261→
262→  for (const project of projects) {
263→    const nameTokens = new Set(
264→      project.name.toLowerCase().replace(/[^a-z0-9]/g, " ").split(/\s+/).filter((t) => t.length > 2),
265→    );
266→    let overlap = 0;
267→    for (const token of nameTokens) {
268→      if (pathTokens.has(token)) overlap++;
269→    }
270→    if (overlap > bestOverlap) {
271→      bestOverlap = overlap;
272→      bestProject = project;
273→    }
274→  }
275→
276→  return bestProject ? bestProject.id : undefined;
277→}
