 190→export async function readEntityName(
 191→  surreal: Surreal,
 192→  record: GraphEntityRecord,
 193→): Promise<string | undefined> {
 194→  const table = record.table.name;
 195→
 196→  if (table === "workspace" || table === "project" || table === "person" || table === "identity" || table === "feature") {
 197→    const row = await surreal.select<{ name: string }>(record as RecordId<typeof table, string>);
 198→    return row?.name;
 199→  }
 200→
 201→  if (table === "task") {
 202→    const row = await surreal.select<{ title: string }>(record as RecordId<"task", string>);
 203→    return row?.title;
 204→  }
 205→
 206→  if (table === "decision") {
 207→    const row = await surreal.select<{ summary: string }>(record as RecordId<"decision", string>);
 208→    return row?.summary;
 209→  }
 210→
 211→  if (table === "policy") {
 212→    const row = await surreal.select<{ title: string }>(record as RecordId<"policy", string>);
 213→    return row?.title;
 214→  }
 215→
 216→  if (table === "intent") {
 217→    const row = await surreal.select<{ goal: string }>(record as RecordId<"intent", string>);
 218→    return row?.goal;
 219→  }
 220→
 221→  if (table === "agent_session") {
 222→    const row = await surreal.select<{ agent: string }>(record as RecordId<"agent_session", string>);
 223→    return row?.agent;
 224→  }
 225→
 226→  if (table === "objective") {
 227→    const row = await surreal.select<{ title: string }>(record as RecordId<"objective", string>);
 228→    return row?.title;
 229→  }
 230→
 231→  if (table === "behavior") {
 232→    const row = await surreal.select<{ metric_type: string; score: number }>(record as RecordId<"behavior", string>);
 233→    return row ? `${row.metric_type} (${row.score.toFixed(2)})` : undefined;
 234→  }
 235→
 236→  const row = await surreal.select<{ text: string }>(record as RecordId<"question", string>);
 237→  return row?.text;
