 268→export async function isEntityInWorkspace(
 269→  surreal: Surreal,
 270→  workspaceRecord: RecordId<"workspace", string>,
 271→  entityRecord: GraphEntityRecord,
 272→): Promise<boolean> {
 273→  const table = entityRecord.table.name;
 274→
 275→  if (table === "workspace") {
 276→    return toRecordIdString(entityRecord) === toRecordIdString(workspaceRecord);
 277→  }
 278→
 279→  if (table === "project") {
 280→    const [rows] = await surreal
 281→      .query<[Array<{ id: RecordId<"has_project", string> }>]>(
 282→        "SELECT id FROM has_project WHERE `in` = $workspace AND out = $project LIMIT 1;",
 283→        { workspace: workspaceRecord, project: entityRecord },
 284→      )
 285→      .collect<[Array<{ id: RecordId<"has_project", string> }>]>();
 286→
 287→    return rows.length > 0;
 288→  }
 289→
 290→  if (table === "person") {
 291→    const [rows] = await surreal
 292→      .query<[Array<{ id: RecordId<"member_of", string> }>]>(
 293→        "SELECT id FROM member_of WHERE `in` = $person AND out = $workspace LIMIT 1;",
 294→        { workspace: workspaceRecord, person: entityRecord },
 295→      )
 296→      .collect<[Array<{ id: RecordId<"member_of", string> }>]>();
 297→
 298→    return rows.length > 0;
 299→  }
 300→
 301→  if (table === "identity") {
 302→    const [rows] = await surreal
 303→      .query<[Array<{ id: RecordId<"identity", string> }>]>(
 304→        "SELECT id FROM identity WHERE id = $identity AND workspace = $workspace;",
 305→        { workspace: workspaceRecord, identity: entityRecord },
 306→      )
 307→      .collect<[Array<{ id: RecordId<"identity", string> }>]>();
 308→
 309→    return rows.length > 0;
 310→  }
 311→
 312→  if (table === "feature") {
 313→    const [rows] = await surreal
 314→      .query<[Array<{ id: RecordId<"feature", string> }>]>(
 315→        "SELECT id FROM feature WHERE id = $feature AND workspace = $workspace;",
 316→        { workspace: workspaceRecord, feature: entityRecord },
 317→      )
 318→      .collect<[Array<{ id: RecordId<"feature", string> }>]>();
 319→
 320→    if (rows.length > 0) {
 321→      return true;
 322→    }
 323→
 324→    // Backward-compatible scope fallback for legacy features that may be
 325→    // linked into workspace projects but are missing the workspace field.
 326→    const [linkedRows] = await surreal
 327→      .query<[Array<{ id: RecordId<"has_feature", string> }>]>(
 328→        [
 329→          "SELECT id FROM has_feature",
 330→          "WHERE out = $feature",
 331→          "AND `in` IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)",
 332→          "LIMIT 1;",
 333→        ].join(" "),
 334→        { workspace: workspaceRecord, feature: entityRecord },
 335→      )
 336→      .collect<[Array<{ id: RecordId<"has_feature", string> }>]>();
 337→
 338→    return linkedRows.length > 0;
 339→  }
 340→
 341→  if (table === "task" || table === "decision" || table === "question" || table === "suggestion" || table === "intent" || table === "agent_session") {
 342→    const [rows] = await surreal
 343→      .query<[Array<{ id: RecordId<string, string> }>]>(
 344→        `SELECT id FROM ${table} WHERE id = $entity AND workspace = $workspace;`,
 345→        { workspace: workspaceRecord, entity: entityRecord },
 346→      )
 347→      .collect<[Array<{ id: RecordId<string, string> }>]>();
 348→
 349→    return rows.length > 0;
 350→  }
 351→
 352→  if (table === "policy") {
 353→    const [rows] = await surreal
 354→      .query<[Array<{ id: RecordId<"protects", string> }>]>(
 355→        "SELECT id FROM protects WHERE `in` = $policy AND out = $workspace LIMIT 1;",
 356→        { workspace: workspaceRecord, policy: entityRecord },
 357→      )
 358→      .collect<[Array<{ id: RecordId<"protects", string> }>]>();
 359→
 360→    return rows.length > 0;
 361→  }
 362→
 363→  return false;
 364→}
