 366→export async function listConversationEntities(input: {
 367→  surreal: Surreal;
 368→  conversationRecord: RecordId<"conversation", string>;
 369→  workspaceRecord: RecordId<"workspace", string>;
 370→  limit: number;
 371→  inheritedEntityIds?: RecordId[];
 372→}): Promise<ConversationEntity[]> {
 373→  const [rows] = await input.surreal
 374→    .query<[Array<{ in: RecordId<"message", string>; out: GraphEntityRecord; confidence: number; extracted_at: string | Date }>]>(
 375→      [
 376→        "SELECT `in`, out, confidence, extracted_at",
 377→        "FROM extraction_relation",
 378→        "WHERE `in` IN (SELECT VALUE id FROM message WHERE conversation = $conversation)",
 379→        "ORDER BY extracted_at DESC",
 380→        "LIMIT $limit;",
 381→      ].join(" "),
 382→      {
 383→        conversation: input.conversationRecord,
 384→        limit: input.limit,
 385→      },
 386→    )
 387→    .collect<[Array<{ in: RecordId<"message", string>; out: GraphEntityRecord; confidence: number; extracted_at: string | Date }>]>() ;
 388→
 389→  const items: ConversationEntity[] = [];
 390→  const seen = new Set<string>();
 391→
 392→  for (const row of rows) {
 393→    const table = row.out.table.name as GraphEntityTable;
 394→    // Governance entities (policy, intent, agent_session) are created programmatically,
 395→    // not extracted from message text. They appear in graph views via workspace queries.
 396→    if (
 397→      table !== "workspace" &&
 398→      table !== "project" &&
 399→      table !== "person" &&
 400→      table !== "feature" &&
 401→      table !== "task" &&
 402→      table !== "decision" &&
 403→      table !== "question" &&
 404→      table !== "suggestion"
 405→    ) {
 406→      continue;
 407→    }
 408→
 409→    const scoped = await isEntityInWorkspace(input.surreal, input.workspaceRecord, row.out);
 410→    if (!scoped) {
 411→      continue;
 412→    }
 413→
 414→    const entityKey = `${table}:${toRecordIdString(row.out)}`;
 415→    if (seen.has(entityKey)) {
 416→      continue;
 417→    }
 418→
 419→    const name = await readEntityName(input.surreal, row.out);
 420→    if (!name) {
 421→      continue;
 422→    }
 423→
 424→    items.push({
 425→      id: toRecordIdString(row.out),
 426→      kind: table,
 427→      name,
 428→      confidence: row.confidence,
 429→      sourceMessageId: toRecordIdString(row.in),
 430→    });
 431→    seen.add(entityKey);
 432→  }
 433→
 434→  // Merge inherited entities from parent conversation when branch has sparse context
 435→  if (input.inheritedEntityIds && input.inheritedEntityIds.length > 0 && items.length < 5) {
 436→    const [inheritedRows] = await input.surreal
 437→      .query<[Array<{ in: RecordId<"message", string>; out: GraphEntityRecord; confidence: number; extracted_at: string | Date }>]>(
 438→        [
 439→          "SELECT `in`, out, confidence, extracted_at",
 440→          "FROM extraction_relation",
 441→          "WHERE out IN $entityIds",
 442→          "ORDER BY extracted_at DESC",
 443→          "LIMIT $limit;",
 444→        ].join(" "),
 445→        { entityIds: input.inheritedEntityIds, limit: input.limit },
 446→      )
 447→      .collect<[Array<{ in: RecordId<"message", string>; out: GraphEntityRecord; confidence: number; extracted_at: string | Date }>]>();
 448→
 449→    for (const row of inheritedRows) {
 450→      const table = row.out.table.name as GraphEntityTable;
 451→      if (
 452→        table !== "workspace" &&
 453→        table !== "project" &&
 454→        table !== "person" &&
 455→        table !== "feature" &&
 456→        table !== "task" &&
 457→        table !== "decision" &&
 458→        table !== "question" &&
 459→        table !== "suggestion"
 460→      ) {
 461→        continue;
 462→      }
 463→
 464→      const entityKey = `${table}:${toRecordIdString(row.out)}`;
 465→      if (seen.has(entityKey)) continue;
 466→
 467→      const name = await readEntityName(input.surreal, row.out);
 468→      if (!name) continue;
 469→
 470→      items.push({
 471→        id: toRecordIdString(row.out),
 472→        kind: table,
 473→        name,
 474→        confidence: row.confidence,
 475→        sourceMessageId: toRecordIdString(row.in),
 476→      });
 477→      seen.add(entityKey);
 478→    }
 479→  }
 480→
 481→  return items;
 482→}
