 628→export async function resolveWorkspaceProjectRecord(input: {
 629→  surreal: Surreal;
 630→  workspaceRecord: RecordId<"workspace", string>;
 631→  projectInput: string;
 632→}): Promise<RecordId<"project", string>> {
 633→  const projectInput = input.projectInput.trim();
 634→  if (projectInput.length === 0) {
 635→    throw new Error("project identifier is required");
 636→  }
 637→
 638→  if (projectInput.includes(":")) {
 639→    const projectRecord = parseRecordIdString(projectInput, ["project"]);
 640→    const scoped = await isEntityInWorkspace(input.surreal, input.workspaceRecord, projectRecord);
 641→    if (!scoped) {
 642→      throw new Error("project is not linked to this workspace");
 643→    }
 644→    return projectRecord;
 645→  }
 646→
 647→  const projects = await getWorkspaceProjectRows(input.surreal, input.workspaceRecord);
 648→  const normalized = normalizeSearchValue(projectInput);
 649→
 650→  const exactMatch = projects.find((project) => normalizeSearchValue(project.name) === normalized);
 651→  if (exactMatch) {
 652→    return exactMatch.id;
 653→  }
 654→
 655→  const fuzzyMatches = projects.filter((project) => normalizeSearchValue(project.name).includes(normalized));
 656→  if (fuzzyMatches.length === 1) {
 657→    return fuzzyMatches[0].id;
 658→  }
 659→
 660→  if (fuzzyMatches.length > 1) {
 661→    throw new Error(`project input is ambiguous: ${fuzzyMatches.map((project) => project.name).join(", ")}`);
 662→  }
 663→
 664→  throw new Error(`project not found in workspace: ${projectInput}`);
 665→}
