 955→export async function listEntityNeighbors(input: {
 956→  surreal: Surreal;
 957→  workspaceRecord: RecordId<"workspace", string>;
 958→  entityRecord: GraphEntityRecord;
 959→  limit: number;
 960→}): Promise<EntityNeighbor[]> {
 961→  const [rows] = await input.surreal
 962→    .query<[UnifiedEdgeRow[]]>(
 963→      "RETURN fn::entity_edges($entity, $limit);",
 964→      { entity: input.entityRecord, limit: input.limit },
 965→    )
 966→    .collect<[UnifiedEdgeRow[]]>();
 967→
 968→  const neighbors: EntityNeighbor[] = [];
 969→  const seen = new Set<string>();
 970→
 971→  for (const row of rows) {
 972→    const edgeTable = row.id.table.name;
 973→    const relationKind = row.kind ?? edgeTable;
 974→    const direction = toRecordIdString(row.in) === toRecordIdString(input.entityRecord) ? "outgoing" : "incoming";
 975→    const neighborRecord = direction === "outgoing" ? row.out : row.in;
 976→    const key = `${relationKind}:${toRecordIdString(neighborRecord)}`;
 977→    if (seen.has(key)) continue;
 978→
 979→    const scoped = await isEntityInWorkspace(input.surreal, input.workspaceRecord, neighborRecord as GraphEntityRecord);
 980→    if (!scoped) continue;
 981→
 982→    const name = await readEntityName(input.surreal, neighborRecord as GraphEntityRecord);
 983→    if (!name) continue;
 984→
 985→    seen.add(key);
 986→    neighbors.push({
 987→      id: toRecordIdString(neighborRecord),
 988→      kind: neighborRecord.table.name as GraphEntityTable,
 989→      name,
 990→      relationKind,
 991→      direction,
 992→      confidence: row.confidence ?? 1.0,
 993→    });
 994→  }
 995→
 996→  if (input.entityRecord.table.name !== "task") {
 997→    return neighbors;
 998→  }
 999→
1000→  const hasDirectFeatureRelation = neighbors.some((neighbor) =>
1001→    neighbor.kind === "feature" && (neighbor.relationKind === "belongs_to" || neighbor.relationKind === "has_task")
1002→  );
1003→  if (hasDirectFeatureRelation) {
1004→    return neighbors.filter((neighbor) =>
1005→      !(neighbor.kind === "project" && neighbor.relationKind === "belongs_to" && neighbor.direction === "outgoing")
1006→    );
1007→  }
1008→
1009→  const projectRelation = neighbors.find((neighbor) =>
1010→    neighbor.kind === "project" && neighbor.relationKind === "belongs_to" && neighbor.direction === "outgoing"
1011→  );
1012→  if (!projectRelation) {
1013→    return neighbors;
1014→  }
1015→
1016→  const taskName = await readEntityName(input.surreal, input.entityRecord);
1017→  if (!taskName) {
1018→    return neighbors;
1019→  }
1020→
1021→  const projectRecord = new RecordId("project", projectRelation.id);
1022→  const [featureRows] = await input.surreal
1023→    .query<[Array<{ id: RecordId<"feature", string>; name: string }>]>(
1024→      "SELECT out AS id, out.name AS name FROM has_feature WHERE `in` = $project;",
1025→      { project: projectRecord },
1026→    )
1027→    .collect<[Array<{ id: RecordId<"feature", string>; name: string }>]>();
1028→
1029→  const matches = featureRows.filter((row) => normalizeSearchValue(row.name) === normalizeSearchValue(taskName));
1030→  if (matches.length !== 1) {
1031→    return neighbors;
1032→  }
1033→
1034→  const featureMatch = matches[0];
1035→  const withoutProject = neighbors.filter((neighbor) =>
1036→    !(neighbor.kind === "project" && neighbor.relationKind === "belongs_to" && neighbor.direction === "outgoing")
1037→  );
1038→
1039→  withoutProject.push({
1040→    id: toRecordIdString(featureMatch.id),
1041→    kind: "feature",
1042→    name: featureMatch.name,
1043→    relationKind: "belongs_to",
1044→    direction: "outgoing",
1045→    confidence: 1.0,
1046→  });
1047→
1048→  return withoutProject;
1049→}
