1051→/** Maps entity tables to their identity-referencing owner field */
1052→const IDENTITY_OWNER_FIELDS: Partial<Record<GraphEntityTable, string>> = {
1053→  task: "owner",
1054→  decision: "decided_by",
1055→  feature: "owner",
1056→};
1057→
1058→async function resolveEntityAttribution(
1059→  surreal: Surreal,
1060→  entityRecord: GraphEntityRecord,
1061→  table: GraphEntityTable,
1062→): Promise<IdentityAttribution | undefined> {
1063→  const ownerField = IDENTITY_OWNER_FIELDS[table];
1064→  if (!ownerField) return undefined;
1065→
1066→  // Step 1: get actor identity from owner field
1067→  const [actorRows] = await surreal
1068→    .query<[Array<{ actor_name: string; actor_type: string; owner_id: RecordId }>]>(
1069→      `SELECT ${ownerField}.name AS actor_name, ${ownerField}.type AS actor_type, ${ownerField} AS owner_id FROM $record;`,
1070→      { record: entityRecord },
1071→    )
1072→    .collect<[Array<{ actor_name: string; actor_type: string; owner_id: RecordId }>]>();
1073→
1074→  if (actorRows.length === 0 || !actorRows[0].actor_name) return undefined;
1075→
1076→  const { actor_name, actor_type, owner_id } = actorRows[0];
1077→  const actorType = actor_type as "human" | "agent" | "system";
1078→
1079→  if (actorType === "human" || actorType === "system") {
1080→    return { actorName: actor_name, actorType };
1081→  }
1082→
1083→  // Step 2: for agent identities, resolve managed_by chain
1084→  const [managedByRows] = await surreal
1085→    .query<[Array<{ managed_by_name: Array<string> }>]>(
1086→      `SELECT ->identity_agent->agent.managed_by.name AS managed_by_name FROM $identity;`,
1087→      { identity: owner_id },
1088→    )
1089→    .collect<[Array<{ managed_by_name: Array<string> }>]>();
1090→
1091→  const accountableHumanName = managedByRows[0]?.managed_by_name?.[0];
1092→
1093→  return {
1094→    actorName: actor_name,
1095→    actorType,
1096→    ...(accountableHumanName ? { accountableHumanName } : {}),
1097→  };
1098→}
