1100→export async function getEntityDetail(input: {
1101→  surreal: Surreal;
1102→  workspaceRecord: RecordId<"workspace", string>;
1103→  entityRecord: GraphEntityRecord;
1104→}): Promise<EntityDetail> {
1105→  const scoped = await isEntityInWorkspace(input.surreal, input.workspaceRecord, input.entityRecord);
1106→  if (!scoped) {
1107→    throw new Error("entity is outside the current workspace scope");
1108→  }
1109→
1110→  const table = input.entityRecord.table.name as GraphEntityTable;
1111→  const row = await input.surreal.select<Record<string, unknown>>(input.entityRecord);
1112→  if (!row) {
1113→    throw new Error(`entity not found: ${table}:${toRecordIdString(input.entityRecord)}`);
1114→  }
1115→
1116→  const name = await readEntityName(input.surreal, input.entityRecord);
1117→  if (!name) {
1118→    throw new Error(`entity has no readable name field: ${table}:${toRecordIdString(input.entityRecord)}`);
1119→  }
1120→
1121→  const relationships = await listEntityNeighbors({
1122→    surreal: input.surreal,
1123→    workspaceRecord: input.workspaceRecord,
1124→    entityRecord: input.entityRecord,
1125→    limit: 40,
1126→  });
1127→
1128→  const [provenanceRows] = await input.surreal
1129→    .query<[
1130→      Array<{
1131→        in: RecordId<"message" | "document_chunk" | "git_commit", string>;
1132→        confidence: number;
1133→        extracted_at: string | Date;
1134→        evidence?: string;
1135→        evidence_source?: RecordId<"message", string>;
1136→        resolved_from?: RecordId<"message", string>;
1137→        from_text?: string;
1138→      }>,
1139→    ]>(
1140→      [
1141→        "SELECT `in`, confidence, extracted_at, evidence, evidence_source, resolved_from, from_text",
1142→        "FROM extraction_relation",
1143→        "WHERE out = $entity",
1144→        "AND (",
1145→        "  `in` IN (",
1146→        "    SELECT VALUE id",
1147→        "    FROM message",
1148→        "    WHERE conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace)",
1149→        "  )",
1150→        "  OR `in` IN (SELECT VALUE id FROM document_chunk WHERE workspace = $workspace)",
1151→        "  OR `in` IN (SELECT VALUE id FROM git_commit WHERE workspace = $workspace)",
1152→        ")",
1153→        "ORDER BY extracted_at DESC",
1154→        "LIMIT 40;",
1155→      ].join(" "),
1156→      {
1157→        workspace: input.workspaceRecord,
1158→        entity: input.entityRecord,
1159→      },
1160→    )
1161→    .collect<[
1162→      Array<{
1163→        in: RecordId<"message" | "document_chunk" | "git_commit", string>;
1164→        confidence: number;
1165→        extracted_at: string | Date;
1166→        evidence?: string;
1167→        evidence_source?: RecordId<"message", string>;
1168→        resolved_from?: RecordId<"message", string>;
1169→        from_text?: string;
1170→      }>,
1171→    ]>();
1172→
1173→  // Resolve conversationIds for message-type provenance sources
1174→  const messageProvenanceRows = provenanceRows.filter((r) => r.in.table.name === "message");
1175→  let convMap: Map<string, string> | undefined;
1176→  if (messageProvenanceRows.length > 0) {
1177→    const [convRows] = await input.surreal
1178→      .query<[Array<{ id: RecordId<"message", string>; conversation: RecordId<"conversation", string> }>]>(
1179→        "SELECT id, conversation FROM message WHERE id IN $ids;",
1180→        { ids: messageProvenanceRows.map((r) => r.in) },
1181→      )
1182→      .collect<[Array<{ id: RecordId<"message", string>; conversation: RecordId<"conversation", string> }>]>();
1183→    convMap = new Map(convRows.map((r) => [r.id.id as string, r.conversation.id as string]));
1184→  }
1185→
1186→  const provenance = provenanceRows.map((row) => ({
1187→    sourceId: toRecordIdString(row.in),
1188→    sourceKind: row.in.table.name === "document_chunk"
1189→      ? "document_chunk"
1190→      : row.in.table.name === "git_commit"
1191→        ? "git_commit"
1192→        : "message",
1193→    confidence: row.confidence,
1194→    extractedAt: toIsoString(row.extracted_at),
1195→    ...(row.in.table.name === "message" && convMap?.get(row.in.id as string)
1196→      ? { conversationId: convMap.get(row.in.id as string) }
1197→      : {}),
1198→    ...(row.evidence ? { evidence: row.evidence } : {}),
1199→    ...(row.evidence_source ? { evidenceSource: toRecordIdString(row.evidence_source) } : {}),
1200→    ...(row.resolved_from ? { resolvedFrom: toRecordIdString(row.resolved_from) } : {}),
1201→    ...(row.from_text ? { fromText: row.from_text } : {}),
1202→  } satisfies EntityProvenance));
1203→
1204→  // Resolve identity attribution for entities with an owner field
1205→  const attribution = await resolveEntityAttribution(input.surreal, input.entityRecord, table);
1206→
1207→  return {
1208→    entity: {
1209→      id: toRecordIdString(input.entityRecord),
1210→      kind: table,
1211→      name,
1212→      data: row,
1213→      ...(attribution?.actorType ? { identityType: attribution.actorType } : {}),
1214→      ...(attribution ? { attribution } : {}),
1215→    },
1216→    relationships,
1217→    provenance,
1218→  };
1219→}
