1221→export async function getProjectStatus(input: {
1222→  surreal: Surreal;
1223→  workspaceRecord: RecordId<"workspace", string>;
1224→  projectInput: string;
1225→}): Promise<ProjectStatus> {
1226→  const projectRecord = await resolveWorkspaceProjectRecord({
1227→    surreal: input.surreal,
1228→    workspaceRecord: input.workspaceRecord,
1229→    projectInput: input.projectInput,
1230→  });
1231→
1232→  const project = await input.surreal.select<{ id: RecordId<"project", string>; name: string }>(projectRecord);
1233→  if (!project) {
1234→    throw new Error(`project not found: ${toRecordIdString(projectRecord)}`);
1235→  }
1236→
1237→  const [featureRows] = await input.surreal
1238→    .query<[Array<{ id: RecordId<"feature", string>; name: string; status: string }>]>(
1239→      "SELECT id, name, status FROM feature WHERE id IN (SELECT VALUE out FROM has_feature WHERE `in` = $project);",
1240→      { project: projectRecord },
1241→    )
1242→    .collect<[Array<{ id: RecordId<"feature", string>; name: string; status: string }>]>();
1243→
1244→  const [taskRows] = await input.surreal
1245→    .query<[Array<{ id: RecordId<"task", string>; title: string; status: string; priority?: string; created_at: string | Date }>]>(
1246→      [
1247→        "SELECT id, title, status, priority, created_at",
1248→        "FROM task",
1249→        "WHERE id IN (SELECT VALUE `in` FROM belongs_to WHERE out = $project)",
1250→        "OR id IN (",
1251→        "  SELECT VALUE out",
1252→        "  FROM has_task",
1253→        "  WHERE `in` IN (SELECT VALUE out FROM has_feature WHERE `in` = $project)",
1254→        ")",
1255→        "ORDER BY created_at DESC",
1256→        "LIMIT 100;",
1257→      ].join(" "),
1258→      { project: projectRecord },
1259→    )
1260→    .collect<[Array<{ id: RecordId<"task", string>; title: string; status: string; priority?: string; created_at: string | Date }>]>();
1261→
1262→  const [decisionRows] = await input.surreal
1263→    .query<[Array<{ id: RecordId<"decision", string>; summary: string; status: string; priority?: string; created_at: string | Date }>]>(
1264→      [
1265→        "SELECT id, summary, status, priority, created_at",
1266→        "FROM decision",
1267→        "WHERE id IN (SELECT VALUE `in` FROM belongs_to WHERE out = $project)",
1268→        "ORDER BY created_at DESC",
1269→        "LIMIT 30;",
1270→      ].join(" "),
1271→      { project: projectRecord },
1272→    )
1273→    .collect<[Array<{ id: RecordId<"decision", string>; summary: string; status: string; priority?: string; created_at: string | Date }>]>();
1274→
1275→  const [questionRows] = await input.surreal
1276→    .query<[Array<{ id: RecordId<"question", string>; text: string; status: string; priority?: string; created_at: string | Date }>]>(
1277→      [
1278→        "SELECT id, text, status, priority, created_at",
1279→        "FROM question",
1280→        "WHERE id IN (SELECT VALUE `in` FROM belongs_to WHERE out = $project)",
1281→        "ORDER BY created_at DESC",
1282→        "LIMIT 30;",
1283→      ].join(" "),
1284→      { project: projectRecord },
1285→    )
1286→    .collect<[Array<{ id: RecordId<"question", string>; text: string; status: string; priority?: string; created_at: string | Date }>]>();
1287→
1288→  let active = 0;
1289→  let completed = 0;
1290→  let blocked = 0;
1291→
1292→  for (const task of taskRows) {
1293→    const normalized = task.status.trim().toLowerCase();
1294→    if (normalized === "blocked") {
1295→      blocked += 1;
1296→      continue;
1297→    }
1298→
1299→    if (normalized === "done" || normalized === "completed") {
1300→      completed += 1;
1301→      continue;
1302→    }
1303→
1304→    active += 1;
1305→  }
1306→
1307→  return {
1308→    project: {
1309→      id: toRecordIdString(project.id),
1310→      name: project.name,
1311→    },
1312→    tasks: {
1313→      active,
1314→      completed,
1315→      blocked,
1316→      recent: taskRows.slice(0, 20).map((task) => ({
1317→        id: toRecordIdString(task.id),
1318→        name: task.title,
1319→        status: task.status,
1320→        ...(task.priority ? { priority: task.priority } : {}),
1321→      })),
1322→    },
1323→    decisions: decisionRows.map((decision) => ({
1324→      id: toRecordIdString(decision.id),
1325→      name: decision.summary,
1326→      status: decision.status,
1327→      ...(decision.priority ? { priority: decision.priority } : {}),
1328→    })),
1329→    questions: questionRows.map((question) => ({
1330→      id: toRecordIdString(question.id),
1331→      name: question.text,
1332→      status: question.status,
1333→      ...(question.priority ? { priority: question.priority } : {}),
1334→    })),
1335→    features: featureRows.map((feature) => ({
1336→      id: toRecordIdString(feature.id),
1337→      name: feature.name,
1338→      status: feature.status,
1339→    })),
1340→  };
1341→}
