1343→export async function searchConversationMessagesByEmbedding(input: {
1344→  surreal: Surreal;
1345→  workspaceRecord: RecordId<"workspace", string>;
1346→  queryEmbedding: number[];
1347→  projectRecord?: RecordId<"project", string>;
1348→  limit: number;
1349→}): Promise<RankedMessage[]> {
1350→  let rows: Array<{ id: RecordId<"message", string>; conversation: RecordId<"conversation", string>; text: string; createdAt: string | Date; embedding?: number[] }> = [];
1351→
1352→  if (input.projectRecord) {
1353→    const [projectEntityRows] = await input.surreal
1354→      .query<[Array<RecordId<"task" | "decision" | "question", string>>]>(
1355→        "SELECT VALUE `in` FROM belongs_to WHERE out = $project;",
1356→        { project: input.projectRecord },
1357→      )
1358→      .collect<[Array<RecordId<"task" | "decision" | "question", string>>]>();
1359→
1360→    const scopedEntities: Array<RecordId<string, string>> = [input.projectRecord, ...projectEntityRows];
1361→
1362→    const [messageRows] = await input.surreal
1363→      .query<[
1364→        Array<{
1365→          id: RecordId<"message", string>;
1366→          conversation: RecordId<"conversation", string>;
1367→          text: string;
1368→          createdAt: string | Date;
1369→          embedding?: number[];
1370→        }>,
1371→      ]>(
1372→        [
1373→          "SELECT id, conversation, text, createdAt, embedding",
1374→          "FROM message",
1375→          "WHERE embedding != NONE",
1376→          "AND conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace)",
1377→          "AND id IN (SELECT VALUE `in` FROM extraction_relation WHERE out IN $entities)",
1378→          "ORDER BY createdAt DESC",
1379→          "LIMIT $limit;",
1380→        ].join(" "),
1381→        {
1382→          workspace: input.workspaceRecord,
1383→          entities: scopedEntities,
1384→          limit: Math.max(input.limit * 25, 250),
1385→        },
1386→      )
1387→      .collect<[
1388→        Array<{
1389→          id: RecordId<"message", string>;
1390→          conversation: RecordId<"conversation", string>;
1391→          text: string;
1392→          createdAt: string | Date;
1393→          embedding?: number[];
1394→        }>,
1395→      ]>();
1396→
1397→    rows = messageRows;
1398→  } else {
1399→    const [messageRows] = await input.surreal
1400→      .query<[
1401→        Array<{
1402→          id: RecordId<"message", string>;
1403→          conversation: RecordId<"conversation", string>;
1404→          text: string;
1405→          createdAt: string | Date;
1406→          embedding?: number[];
1407→        }>,
1408→      ]>(
1409→        [
1410→          "SELECT id, conversation, text, createdAt, embedding",
1411→          "FROM message",
1412→          "WHERE embedding != NONE",
1413→          "AND conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace)",
1414→          "ORDER BY createdAt DESC",
1415→          "LIMIT $limit;",
1416→        ].join(" "),
1417→        {
1418→          workspace: input.workspaceRecord,
1419→          limit: Math.max(input.limit * 25, 250),
1420→        },
1421→      )
1422→      .collect<[
1423→        Array<{
1424→          id: RecordId<"message", string>;
1425→          conversation: RecordId<"conversation", string>;
1426→          text: string;
1427→          createdAt: string | Date;
1428→          embedding?: number[];
1429→        }>,
1430→      ]>();
1431→
1432→    rows = messageRows;
1433→  }
1434→
1435→  const ranked = rows
1436→    .map((row) => ({
1437→      row,
1438→      score: row.embedding ? cosineSimilarity(input.queryEmbedding, row.embedding) : -1,
1439→    }))
1440→    .filter((row) => row.score > 0)
1441→    .sort((a, b) => b.score - a.score)
1442→    .slice(0, input.limit)
1443→    .map((item) => ({
1444→      id: toRecordIdString(item.row.id),
1445→      conversationId: toRecordIdString(item.row.conversation),
1446→      text: item.row.text,
1447→      score: item.score,
1448→      createdAt: toIsoString(item.row.createdAt),
1449→    } satisfies RankedMessage));
1450→
1451→  return ranked;
1452→}
