1607→    const workspaceMessageIds = new Set((await getWorkspaceMessageIds(input.surreal, input.workspaceRecord)).map((row) => toRecordIdString(row)));
1608→    if (workspaceMessageIds.has(toRecordIdString(decision.source_message))) {
