1611→  }
1612→
1613→  const [rows] = await input.surreal
1614→    .query<[Array<{ in: RecordId<"message", string> }>]>(
1615→      [
1616→        "SELECT `in`",
1617→        "FROM extraction_relation",
1618→        "WHERE out = $decision",
1619→        "AND `in` IN (",
1620→        "  SELECT VALUE id",
1621→        "  FROM message",
1622→        "  WHERE conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace)",
1623→        ")",
1624→        "ORDER BY extracted_at ASC",
1625→        "LIMIT 1;",
1626→      ].join(" "),
1627→      {
1628→        workspace: input.workspaceRecord,
1629→        decision: input.decisionRecord,
1630→      },
1631→    )
1632→    .collect<[Array<{ in: RecordId<"message", string> }>]>();
1633→
1634→  return rows[0]?.in;
