1731→export function preferTaskFeatureEdges(raw: GraphViewRawResult): GraphViewRawResult {
1732→  const entityById = new Map(raw.entities.map((entity) => [entity.id, entity] as const));
1733→  const taskHasFeatureLink = new Set<string>();
1734→  const projectToFeatures = new Map<string, string[]>();
1735→
1736→  for (const edge of raw.edges) {
1737→    const fromKind = entityById.get(edge.fromId)?.kind;
1738→    const toKind = entityById.get(edge.toId)?.kind;
1739→
1740→    if (edge.kind === "has_task" && fromKind === "feature" && toKind === "task") {
1741→      taskHasFeatureLink.add(edge.toId);
1742→    }
1743→
1744→    if (edge.kind === "belongs_to" && fromKind === "task" && toKind === "feature") {
1745→      taskHasFeatureLink.add(edge.fromId);
1746→    }
1747→
1748→    if (edge.kind === "has_feature" && fromKind === "project" && toKind === "feature") {
1749→      const existing = projectToFeatures.get(edge.fromId) ?? [];
1750→      existing.push(edge.toId);
1751→      projectToFeatures.set(edge.fromId, existing);
1752→    }
1753→  }
1754→
1755→  const normalizedName = (value: string): string => normalizeSearchValue(value);
1756→  const nextEdges: GraphViewRawEdge[] = [];
1757→  const syntheticEdges = new Map<string, GraphViewRawEdge>();
1758→
1759→  for (const edge of raw.edges) {
1760→    const fromKind = entityById.get(edge.fromId)?.kind;
1761→    const toKind = entityById.get(edge.toId)?.kind;
1762→
1763→    if (edge.kind === "belongs_to" && fromKind === "task" && toKind === "project") {
1764→      const taskId = edge.fromId;
1765→      if (taskHasFeatureLink.has(taskId)) {
1766→        continue;
1767→      }
1768→
1769→      const taskName = entityById.get(taskId)?.name;
1770→      if (!taskName) {
1771→        nextEdges.push(edge);
1772→        continue;
1773→      }
1774→
1775→      const featureCandidates = (projectToFeatures.get(edge.toId) ?? []).filter((featureId) => {
1776→        const featureName = entityById.get(featureId)?.name;
1777→        return featureName ? normalizedName(featureName) === normalizedName(taskName) : false;
1778→      });
1779→
1780→      if (featureCandidates.length === 1) {
1781→        const featureId = featureCandidates[0];
1782→        const syntheticId = `inferred_task_feature_${taskId}_${featureId}`;
1783→        syntheticEdges.set(syntheticId, {
1784→          id: syntheticId,
1785→          kind: "belongs_to",
1786→          fromId: taskId,
1787→          toId: featureId,
1788→          confidence: 1.0,
1789→        });
1790→        taskHasFeatureLink.add(taskId);
1791→        continue;
1792→      }
1793→    }
1794→
1795→    nextEdges.push(edge);
1796→  }
1797→
1798→  return {
1799→    entities: raw.entities,
1800→    edges: [...nextEdges, ...syntheticEdges.values()],
1801→  };
1802→}
