1849→export async function getFocusedGraphView(input: {
1850→  surreal: Surreal;
1851→  workspaceRecord: RecordId<"workspace", string>;
1852→  centerEntityRecord: GraphEntityRecord;
1853→  depth: number;
1854→}): Promise<GraphViewRawResult> {
1855→  const clampedDepth = Math.max(1, Math.min(3, input.depth));
1856→
1857→  const scoped = await isEntityInWorkspace(input.surreal, input.workspaceRecord, input.centerEntityRecord);
1858→  if (!scoped) {
1859→    throw new Error("entity is outside the current workspace scope");
1860→  }
1861→
1862→  const collected = new Map<string, GraphEntityRecord>();
1863→  collected.set(toRecordIdString(input.centerEntityRecord), input.centerEntityRecord);
1864→
1865→  let frontier: RecordId<string, string>[] = [input.centerEntityRecord];
1866→
1867→  for (let hop = 0; hop < clampedDepth; hop++) {
1868→    if (frontier.length === 0) {
1869→      break;
1870→    }
1871→
1872→    const nextFrontier: RecordId<string, string>[] = [];
1873→
1874→    const [rows] = await input.surreal
1875→      .query<[Array<{ in: RecordId<string, string>; out: RecordId<string, string> }>]>(
1876→        "RETURN fn::graph_neighbors($currentIds);",
1877→        { currentIds: frontier },
1878→      )
1879→      .collect<[Array<{ in: RecordId<string, string>; out: RecordId<string, string> }>]>();
1880→
1881→    for (const row of rows) {
1882→      for (const endpoint of [row.in, row.out]) {
1883→        const key = toRecordIdString(endpoint);
1884→        if (collected.has(key)) continue;
1885→
1886→        const inScope = await isEntityInWorkspace(input.surreal, input.workspaceRecord, endpoint as GraphEntityRecord);
1887→        if (!inScope) continue;
1888→
1889→        collected.set(key, endpoint as GraphEntityRecord);
1890→        nextFrontier.push(endpoint);
1891→      }
1892→    }
1893→
1894→    frontier = nextFrontier;
1895→  }
1896→
1897→  const allRecords = Array.from(collected.values());
1898→  const entities = await resolveEntityNames(input.surreal, allRecords);
1899→  const edges = await collectEntityRelationEdges(input.surreal, allRecords);
1900→
1901→  return preferTaskFeatureEdges({ entities, edges });
1902→}
