  1→import { randomUUID } from "node:crypto";
  2→import { RecordId, Surreal } from "surrealdb";
  3→import type { embed } from "ai";
  4→import type { EntityCategory, ObservationSeverity, ObservationStatus, ObservationSummary, ObservationType } from "../../shared/contracts";
  5→import { createEmbeddingVector } from "../graph/embeddings";
  6→import { log } from "../telemetry/logger";
  7→
  8→type ObservationRecord = RecordId<"observation", string>;
  9→export type ObserveTargetRecord = RecordId<"project" | "feature" | "task" | "decision" | "question" | "observation" | "intent" | "git_commit" | "objective" | "trace", string>;
 10→
 11→type EmbeddingModel = Parameters<typeof embed>[0]["model"];
 12→
 13→const SEVERITY_PRIORITY: Record<ObservationSeverity, number> = {
 14→  conflict: 0,
 15→  warning: 1,
 16→  info: 2,
 17→};
 18→
 19→const SIMILARITY_THRESHOLD = 0.85;
 20→
 21→// ---------------------------------------------------------------------------
 22→// Cross-agent similarity linking
 23→// ---------------------------------------------------------------------------
 24→
 25→/**
 26→ * Finds semantically similar open observations and creates similar_to edges.
 27→ * Surfaces convergence — multiple agents or sessions independently flagging
 28→ * the same issue is a stronger signal than a single observation.
 29→ */
 30→async function linkSimilarObservations(input: {
 31→  surreal: Surreal;
 32→  workspaceRecord: RecordId<"workspace", string>;
 33→  observationRecord: RecordId<"observation", string>;
 34→  embedding: number[];
 35→  now: Date;
 36→}): Promise<void> {
 37→  const sql = `
 38→    LET $candidates = SELECT id, workspace, status,
 39→      vector::similarity::cosine(embedding, $vec) AS similarity
 40→      FROM observation WHERE embedding <|10, COSINE|> $vec;
 41→    SELECT id, similarity FROM $candidates
 42→      WHERE workspace = $ws AND id != $self
 43→      AND status IN ['open', 'acknowledged']
 44→      AND similarity > ${SIMILARITY_THRESHOLD}
 45→      ORDER BY similarity DESC LIMIT 5;
 46→  `;
 47→
 48→  const results = await input.surreal.query<[null, Array<{ id: RecordId<"observation", string>; similarity: number }>]>(sql, {
 49→    vec: input.embedding,
 50→    ws: input.workspaceRecord,
 51→    self: input.observationRecord,
 52→  });
 53→
 54→  const similar = results[1] ?? [];
 55→  for (const match of similar) {
 56→    await input.surreal
 57→      .relate(input.observationRecord, new RecordId("similar_to", randomUUID()), match.id, {
 58→        similarity: match.similarity,
 59→        created_at: input.now,
 60→      })
 61→      .output("after");
 62→  }
 63→
 64→  if (similar.length > 0) {
 65→    log.info("observation.similar_linked", "Linked similar cross-agent observations", {
 66→      observationId: input.observationRecord.id,
 67→      linkedCount: similar.length,
 68→    });
 69→  }
 70→}
 71→
 72→// ---------------------------------------------------------------------------
 73→// Create or deduplicate observation
 74→// ---------------------------------------------------------------------------
 75→
 76→export type EmbeddingDeps = {
 77→  embeddingModel: EmbeddingModel;
 78→  embeddingDimension: number;
 79→};
 80→
 81→export async function createObservation(input: {
 82→  surreal: Surreal;
 83→  workspaceRecord: RecordId<"workspace", string>;
 84→  text: string;
 85→  severity: ObservationSeverity;
 86→  category?: EntityCategory;
 87→  observationType?: ObservationType;
 88→  sourceAgent: string;
 89→  now: Date;
 90→  sourceMessageRecord?: RecordId<"message", string>;
 91→  sourceSessionRecord?: RecordId<"agent_session", string>;
 92→  relatedRecords?: ObserveTargetRecord[];
 93→  embedding?: number[];
 94→  confidence?: number;
 95→  evidenceRefs?: RecordId[];
 96→  verified?: boolean;
 97→  source?: string;
 98→  reasoning?: string;
 99→  embeddingDeps?: EmbeddingDeps;
100→}): Promise<ObservationRecord> {
101→  // Step 1: Resolve embedding — use provided or generate from text
102→  let embedding = input.embedding;
103→  if (!embedding && input.embeddingDeps) {
104→    embedding = await createEmbeddingVector(
105→      input.embeddingDeps.embeddingModel,
106→      input.text,
107→      input.embeddingDeps.embeddingDimension,
108→    );
109→  }
110→
111→  // Step 2: Create new observation
112→  const observationRecord = new RecordId("observation", randomUUID());
113→
114→  await input.surreal.create(observationRecord).content({
115→    text: input.text,
116→    severity: input.severity,
117→    status: "open",
118→    ...(input.category ? { category: input.category } : {}),
119→    ...(input.observationType ? { observation_type: input.observationType } : {}),
120→    source_agent: input.sourceAgent,
121→    workspace: input.workspaceRecord,
122→    ...(input.sourceMessageRecord ? { source_message: input.sourceMessageRecord } : {}),
123→    ...(input.sourceSessionRecord ? { source_session: input.sourceSessionRecord } : {}),
124→    ...(embedding ? { embedding } : {}),
125→    ...(input.confidence !== undefined ? { confidence: input.confidence } : {}),
126→    ...(input.evidenceRefs && input.evidenceRefs.length > 0 ? { evidence_refs: input.evidenceRefs } : {}),
127→    ...(input.verified !== undefined ? { verified: input.verified } : {}),
128→    ...(input.source ? { source: input.source } : {}),
129→    ...(input.reasoning !== undefined ? { reasoning: input.reasoning } : {}),
130→    created_at: input.now,
131→    updated_at: input.now,
132→  });
133→
134→  // Create observes edges to related entities
135→  const targets: ObserveTargetRecord[] = input.relatedRecords ?? [];
136→
137→  for (const target of targets) {
138→    await input.surreal
139→      .relate(observationRecord, new RecordId("observes", randomUUID()), target, {
140→        added_at: input.now,
141→      })
142→      .output("after");
143→  }
144→
145→  // Step 4: Link cross-agent similar observations via similar_to edges
146→  if (embedding) {
147→    await linkSimilarObservations({
148→      surreal: input.surreal,
149→      workspaceRecord: input.workspaceRecord,
150→      observationRecord,
151→      embedding,
152→      now: input.now,
153→    }).catch((error) => {
154→      log.warn("observation.similar_link_failed", "Failed to link similar observations", {
155→        observationId: observationRecord.id,
156→        error: error instanceof Error ? error.message : String(error),
157→      });
158→    });
159→  }
160→
161→  return observationRecord;
162→}
