164→export async function acknowledgeObservation(input: {
165→  surreal: Surreal;
166→  workspaceRecord: RecordId<"workspace", string>;
167→  observationRecord: ObservationRecord;
168→  now: Date;
169→}): Promise<void> {
170→  const row = await input.surreal.select<{ workspace: RecordId<"workspace", string> }>(input.observationRecord);
171→  if (!row) {
172→    throw new Error(`observation not found: ${input.observationRecord.id as string}`);
173→  }
174→
175→  if ((row.workspace.id as string) !== (input.workspaceRecord.id as string)) {
176→    throw new Error("observation is outside the current workspace scope");
177→  }
178→
179→  await input.surreal.update(input.observationRecord).merge({
180→    status: "acknowledged" satisfies ObservationStatus,
181→    updated_at: input.now,
182→  });
183→}
