235→export type ReasoningObservationResult = {
236→  id: string;
237→  text: string;
238→  reasoning?: string;
239→  severity: ObservationSeverity;
240→  confidence?: number;
241→  sourceAgent: string;
242→  observationType?: ObservationType;
243→  evidenceRefs?: string[];
244→  createdAt: string;
245→};
