247→const DEFAULT_REASONING_LIMIT = 50;
248→
249→function formatReasoningRow(row: ReasoningObservationRow): ReasoningObservationResult {
250→  return {
251→    id: row.id.id as string,
252→    text: row.text,
253→    ...(row.reasoning !== undefined ? { reasoning: row.reasoning } : {}),
254→    severity: row.severity,
255→    ...(row.confidence !== undefined ? { confidence: row.confidence } : {}),
256→    sourceAgent: row.source_agent,
257→    ...(row.observation_type ? { observationType: row.observation_type } : {}),
258→    ...(row.evidence_refs && row.evidence_refs.length > 0
259→      ? { evidenceRefs: row.evidence_refs.map((ref) => ref.id as string) }
260→      : {}),
261→    createdAt:
262→      row.created_at instanceof Date
263→        ? row.created_at.toISOString()
264→        : new Date(row.created_at).toISOString(),
265→  };
266→}
