268→/**
269→ * Returns observations that have LLM reasoning attached, scoped to a workspace.
270→ * Ordered by creation date descending (most recent first).
271→ */
272→export async function listObservationsWithReasoning(input: {
273→  surreal: Surreal;
274→  workspaceRecord: RecordId<"workspace", string>;
275→  limit?: number;
276→  since?: Date;
277→}): Promise<ReasoningObservationResult[]> {
278→  const limit = input.limit ?? DEFAULT_REASONING_LIMIT;
279→
280→  const sinceClause = input.since ? "AND created_at >= $since" : "";
281→  const query = [
282→    "SELECT id, text, reasoning, severity, confidence, source_agent, observation_type, evidence_refs, created_at",
283→    "FROM observation",
284→    `WHERE workspace = $workspace AND reasoning IS NOT NONE ${sinceClause}`,
285→    "ORDER BY created_at DESC",
286→    "LIMIT $limit;",
287→  ].join(" ");
288→
289→  const params: Record<string, unknown> = {
290→    workspace: input.workspaceRecord,
291→    limit,
292→  };
293→  if (input.since) {
294→    params.since = input.since;
295→  }
296→
297→  const [rows] = await input.surreal
298→    .query<[ReasoningObservationRow[]]>(query, params)
299→    .collect<[ReasoningObservationRow[]]>();
300→
301→  return rows.map(formatReasoningRow);
302→}
