317→      [
318→        "SELECT id, text, reasoning, severity, confidence, source_agent, observation_type, evidence_refs, created_at",
319→        "FROM observation",
320→        "WHERE workspace = $workspace AND reasoning IS NONE",
321→        "ORDER BY created_at DESC",
322→        "LIMIT $limit;",
323→      ].join(" "),
