331→export async function listWorkspaceOpenObservations(input: {
332→  surreal: Surreal;
333→  workspaceRecord: RecordId<"workspace", string>;
334→  limit: number;
335→}): Promise<ObservationSummary[]> {
336→  const [rows] = await input.surreal
337→    .query<[OpenObservationRow[]]>(
338→      [
339→        "SELECT id, text, severity, status, category, source_agent, created_at",
340→        "FROM observation",
341→        "WHERE workspace = $workspace",
342→        "AND status IN ['open', 'acknowledged']",
343→        "ORDER BY created_at DESC",
344→        "LIMIT $limit;",
345→      ].join(" "),
346→      {
347→        workspace: input.workspaceRecord,
348→        limit: input.limit,
349→      },
350→    )
351→    .collect<[OpenObservationRow[]]>();
352→
353→  return rows
354→    .slice()
355→    .sort((a, b) => {
356→      const severityDelta = SEVERITY_PRIORITY[a.severity] - SEVERITY_PRIORITY[b.severity];
357→      if (severityDelta !== 0) {
358→        return severityDelta;
359→      }
360→
361→      return new Date(b.created_at).getTime() - new Date(a.created_at).getTime();
362→    })
363→    .map((row) => ({
364→      id: row.id.id as string,
365→      text: row.text,
366→      severity: row.severity,
367→      status: row.status,
368→      ...(row.category ? { category: row.category } : {}),
369→      sourceAgent: row.source_agent,
370→      createdAt: row.created_at instanceof Date ? row.created_at.toISOString() : new Date(row.created_at).toISOString(),
371→    }));
372→}
