 1→-- Migration 0049: Define proxy_token table for CLI proxy authentication
 2→--
 3→-- Stores hashed tokens that CLI clients use to authenticate with the LLM proxy.
 4→-- Each token is scoped to a workspace and identity, with expiration and revocation support.
 5→
 6→BEGIN TRANSACTION;
 7→
 8→DEFINE TABLE proxy_token SCHEMAFULL;
 9→
10→-- Token hash (SHA-256 of the raw token; raw token never stored)
11→DEFINE FIELD token_hash ON proxy_token TYPE string;
12→-- Workspace this token is scoped to
13→DEFINE FIELD workspace ON proxy_token TYPE record<workspace>;
14→-- Identity that owns this token
15→DEFINE FIELD identity ON proxy_token TYPE record<identity>;
16→-- Expiration timestamp
17→DEFINE FIELD expires_at ON proxy_token TYPE datetime;
18→-- Creation timestamp
19→DEFINE FIELD created_at ON proxy_token TYPE datetime DEFAULT time::now();
20→-- Revocation flag
21→DEFINE FIELD revoked ON proxy_token TYPE bool DEFAULT false;
22→
23→-- Unique constraint: each token hash must be globally unique
24→DEFINE INDEX idx_proxy_token_hash ON proxy_token FIELDS token_hash UNIQUE;
25→-- Composite index: lookup tokens by identity + workspace
26→DEFINE INDEX idx_proxy_token_identity_workspace ON proxy_token FIELDS identity, workspace;
27→
28→COMMIT TRANSACTION;
